import 'dart:typed_data'; import 'package:pdf/pdf.dart'; import 'package:pdf/widgets.dart' as pw; class InvoicePdfService { static const double markup = 1.05; static Future<Uint8List> generateInvoice({required String clientName, required String packageName, required double packageBasePrice, required List<Map<String, dynamic>> extras}) async { final pdf = pw.Document(); pdf.addPage(pw.Page(build: (pw.Context context) { double total = (packageBasePrice * markup); return pw.Column(children: [pwText('JAGSPOOR INVOICE - Rands (R)', style: pwTextStyle(fontWeight: pwFontWeightbold)), pwText('Client: $clientName'), pwText('Package: $packageName - R ${(packageBasePrice * markup)toStringAsFixed()}'), pwDivider(), pwText('TOTAL: R ${totaltoStringAsFixed()}', style: pwTextStyle(fontWeight: pwFontWeightbold))]); })); return pdf.save(); } }
